import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"Fabric auf Windows aktualisieren","description":"Ein Schritt-für-Schritt-Leitfaden zur Aktualisierung von Fabric auf Windows.","frontmatter":{"title":"Fabric auf Windows aktualisieren","description":"Ein Schritt-für-Schritt-Leitfaden zur Aktualisierung von Fabric auf Windows.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"de_de/players/updating-fabric/windows.md","filePath":"translated/de_de/players/updating-fabric/windows.md","lastUpdated":1770561656000}`);var s={name:`de_de/players/updating-fabric/windows.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric auf Windows aktualisieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric auf Windows aktualisieren”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Den Fabric Installer herunterladen <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Den Fabric Installer herunterladen”">​</a></h2><p>Lade die <code>.exe</code> Version des Fabric Installer von der <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a> herunter, indem du auf <code>Download for Windows</code> klickst.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Die <code>.exe</code>-Version für Windows erfordert keine Java-Installation, da sie das im offiziellen Minecraft Launcher enthaltene Java verwendet.</p></div><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Den Fabric Installer ausführen <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Den Fabric Installer ausführen”">​</a></h2><p>Schließe vor dem Ausführen des Installers zuerst Minecraft und den Minecraft Launcher.</p><p>Sobald du den Installer öffnest, solltest du eine Oberfläche wie diese sehen:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer mit &quot;Install&quot; hervorgehoben" loading="lazy"></p><p>Stelle sicher, dass die neue Spielversion und die Loader Version korrekt sind, und klicke dann auf <code>Installieren</code>, um Fabric zu aktualisieren.</p><div class="warning custom-block"><p class="custom-block-title">WICHTIG</p><p>Stelle sicher <code>Profil erstellen</code> abzuwählen, wenn du den Installer ausführst!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Das Profil im Minecraft Launcher aktualisieren <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Das Profil im Minecraft Launcher aktualisieren”">​</a></h2><p>Sobald die Installation abgeschlossen ist, öffne den Minecraft Launcher. Dann wechsle zum <code>Installationen</code> Tab. Finde dein Fabric Profil und öffne dessen Bearbeitungsoberfläche:</p><p><img src="/assets/players/updating-fabric.png" alt="Aktualisieren der Fabric Loader Version im Minecraft Launcher" loading="lazy"></p><p>Ersetze die Version durch die neue Version von Fabric Loader, die du gerade installiert hast, und drücke <code>Speichern</code>.</p><h2 id="4-you-re-done" tabindex="-1">4. Du hast es geschafft! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Du hast es geschafft!”">​</a></h2><p>Sobald du die Schritte abgeschlossen hast, kannst du zur Registerkarte <code>Spielen</code> zurückkehren, das Fabric-Profil aus dem Dropdown-Menü in der linken unteren Ecke auswählen und auf <code>Spielen</code> drücken!</p><p>Wenn du beim Befolgen dieses Leitfadens auf Probleme stößt, kannst du im <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> um Hilfe bitten.</p>`,17)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};